window.QUESTION_PARTS.push([{"stem":"根据《电力市场信息披露基本规则》国能发监管〔2024〕9号售电公司需向公众披露的信息包括（）。","type":"多选","options":[{"label":"A","text":"企业资产证明方式"},{"label":"B","text":"从业人员社保缴纳人数"},{"label":"C","text":"与代理用户签订的购售电合同信息"},{"label":"D","text":"零售套餐产品信息"},{"label":"E","text":"售电公司结算信息"}],"answer":["A","B","D"],"levels":["技师"],"scope":"技师新增","id":"Q1981"},{"stem":"电力交易机构总体负责（）。","type":"多选","options":[{"label":"A","text":"电力现货市场信息披露的实施"},{"label":"B","text":"创造良好的信息披露条件"},{"label":"C","text":"制定信息披露标准格式"},{"label":"D","text":"开放数据接口"},{"label":"E","text":"干预市场交易结果​"}],"answer":["A","B","C","D"],"levels":["技师"],"scope":"技师新增","id":"Q1982"},{"stem":"关于电力市场信息披露的原则和方式，以下（）说法是正确的。","type":"多选","options":[{"label":"A","text":"信息披露应当遵循安全、真实、准确、完整、及时、易于使用的原则。"},{"label":"B","text":"信息披露主体对其披露信息的真实性、准确性、完整性负责。"},{"label":"C","text":"电力交易机构总体负责电力现货市场信息披露的实施，创造良好的信息披露条件。"},{"label":"D","text":"信息披露平台原则上以电力交易中心现有信息平台为基础，信息披露主体按照标准格式通过信息披露平台向电力交易中心提供信息，并通过信息披露平台发布信息。"},{"label":"E","text":"信息披露应以结构化数据为主，非结构化信息采用PDF等文件格式。"}],"answer":["A","B","C","D","E"],"levels":["技师"],"scope":"技师新增","id":"Q1983"},{"stem":"售电公司应当向特定市场成员披露的特定信息包括（）。","type":"多选","options":[{"label":"A","text":"市场交易申报信息。"},{"label":"B","text":"与代理用户签订的购售电合同信息或者协议信息。"},{"label":"C","text":"与发电企业签订的交易合同信息。"},{"label":"D","text":"售电公司批发侧月度结算电量、结算均价。"},{"label":"E","text":"可参与系统调节的响应能力和响应方式等。"}],"answer":["A","B","C","D","E"],"levels":["技师"],"scope":"技师新增","id":"Q1984"},{"stem":"售电公司改善其在电力批发和电力零售市场之间的经营状况，主要方法包括（）。","type":"多选","options":[{"label":"A","text":"改善电力负荷预测技术"},{"label":"B","text":"改善电力市场电价预测技术"},{"label":"C","text":"完善零售电价类型"},{"label":"D","text":"改善定价策略"},{"label":"E","text":"采用风险决策模型制定购售电决策"}],"answer":["A","B","C","D","E"],"levels":["技师"],"scope":"技师新增","id":"Q1985"},{"stem":"以下（）属于天然气价格指数。","type":"多选","options":[{"label":"A","text":"BSPI指数"},{"label":"B","text":"CCTD指数"},{"label":"C","text":"CECI指数"},{"label":"D","text":"CIF指数"},{"label":"E","text":"CLD指数"}],"answer":["D","E"],"levels":["技师"],"scope":"技师新增","id":"Q1986"},{"stem":"预测误差是衡量模型预测准确度的重要指标。常用的误差评估指标包括（）。","type":"多选","options":[{"label":"A","text":"平均绝对误差（MAE）。"},{"label":"B","text":"均方误差（MSE）。"},{"label":"C","text":"均方根误差（RMSE）。"},{"label":"D","text":"R2。"},{"label":"E","text":"相对误差"}],"answer":["A","B","C","D","E"],"levels":["技师"],"scope":"技师新增","id":"Q1987"},{"stem":"电价预测方法包括（）。","type":"多选","options":[{"label":"A","text":"时间序列方法预测"},{"label":"B","text":"机器学习算法预测"},{"label":"C","text":"基于市场均衡的现货价格预测"},{"label":"D","text":"人工智能算法预测"},{"label":"E","text":"基于历史出清价格加权平均"}],"answer":["A","B","C","D"],"levels":["技师"],"scope":"技师新增","id":"Q1988"},{"stem":"电力交易机构向经营主体出具的绿色电力交易结算依据包含以下（）内容。","type":"多选","options":[{"label":"A","text":"绿色电力交易电能量偏差结算费用"},{"label":"B","text":"零售侧绿色电力交易相关结算依据"},{"label":"C","text":"可再生能源补贴费用"},{"label":"D","text":"绿色电力交易电能量结算电量"},{"label":"E","text":"碳排放指标交易费用"}],"answer":["A","B","D"],"levels":["技师"],"scope":"技师新增","id":"Q1989"},{"stem":"发电企业的价格预测主要根据（）方面来分类。","type":"多选","options":[{"label":"A","text":"预测点范围"},{"label":"B","text":"时间长短"},{"label":"C","text":"预测内容"},{"label":"D","text":"预测特性"},{"label":"E","text":"发电成本"}],"answer":["A","B","C","D"],"levels":["技师"],"scope":"技师新增","id":"Q1990"},{"stem":"经营主体注册登记和交易资质审核的目的是（）。","type":"多选","options":[{"label":"A","text":"确保经营主体的真实、完整、准确"},{"label":"B","text":"评估经营主体的经营范围、财务状况、信用记录"},{"label":"C","text":"确定经营主体是否具备参与电力市场的资格和能力"},{"label":"D","text":"关注相关政策法规的变化"},{"label":"E","text":"促进市场竞争的活跃度​"}],"answer":["A","B","C","D"],"levels":["技师"],"scope":"技师新增","id":"Q1991"},{"stem":"监测市场运行和分析市场动态的目的是（）。","type":"多选","options":[{"label":"A","text":"收集市场信息，包括供需情况、价格走势、政策变化"},{"label":"B","text":"运用专业的分析方法和工具对市场信息进行深入剖析和解读"},{"label":"C","text":"帮助经营主体准确把握市场动态和趋势，做出科学的决策"},{"label":"D","text":"提高市场的透明度和公信力"},{"label":"E","text":"直接干预市场价格以稳定市场"}],"answer":["A","B","C","D"],"levels":["技师"],"scope":"技师新增","id":"Q1992"},{"stem":"交易结算和纠纷处理的目的是（）。","type":"多选","options":[{"label":"A","text":"组织和监督交易结算工作，确保交易资金的及时清算和支付"},{"label":"B","text":"核对和确认交易数据，防止出现误差和纠纷"},{"label":"C","text":"调查交易纠纷，提出处理意见并协调和解"},{"label":"D","text":"协助经营主体通过仲裁或诉讼等方式解决纠纷"},{"label":"E","text":"制定市场交易规则和调整交易机制​"}],"answer":["A","B","C","D"],"levels":["技师"],"scope":"技师新增","id":"Q1993"},{"stem":"账号权限设置的目的是（）。","type":"多选","options":[{"label":"A","text":"确保账号只能访问和操作其被授权的资源"},{"label":"B","text":"根据账号的角色和职责进行精细划分"},{"label":"C","text":"采用基于角色的访问控制方法，将权限与角色相关联"},{"label":"D","text":"确保每个账号只能访问和操作其被授权的资源"},{"label":"E","text":"允许所有用户默认拥有最高权限以简化管理​"}],"answer":["A","B","C","D"],"levels":["技师"],"scope":"技师新增","id":"Q1994"},{"stem":"以下（）属于煤炭价格指数。","type":"多选","options":[{"label":"A","text":"BSPI指数"},{"label":"B","text":"CCTD指数"},{"label":"C","text":"CECI指数"},{"label":"D","text":"CIF指数"},{"label":"E","text":"CLD指数"}],"answer":["A","B","C"],"levels":["技师"],"scope":"技师新增","id":"Q1995"},{"stem":"ARMA模型是专门用于拟合非平稳时间序列的模型。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q1996"},{"stem":"数据申报业务主要指各类市场主体通过信息外网申报市场交易相关的各类业务信息的业务活动。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q1997"},{"stem":"发电企业机组检修计划属于公开信息。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q1998"},{"stem":"集中竞价交易可采用边际出清或者高低匹配等价格形成机制。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q1999"},{"stem":"绿色电力交易中，发电企业可以自由选择是否参与交易，无需满足特定的条件。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2000"},{"stem":"某屋顶光伏装机容量为10kW，年发电量在12000kWh左右，据此推算，该屋顶光伏应在三类地区。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2001"},{"stem":"在电力市场中，VaR模型可以直接应用而无需任何改进","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2002"},{"stem":"燃料成本占燃煤发电企业的发电成本不到50%，对发电企业经营管理、市场竞争力具有较大影响。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2003"},{"stem":"激励需求侧资源参与供需互动和电网调峰、提高用户侧用能效率，也是批发市场和零售市场协同的重要环节之一。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2004"},{"stem":"需求响应资源无法参与辅助服务市场。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2005"},{"stem":"省间联络线输电曲线预测是现货市场必须公开的信息。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2006"},{"stem":"电力交易机构应当定期向市场主体出具信息披露报告，内容应当包含但不限于电网概况、电力供需及预测情况、市场准入、市场交易、市场结算、市场建设违规情况、市场干预情况等方面。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2007"},{"stem":"电网企业负责电网概况、电力供需及预测情况、市场准入、市场交易、市场结算、市场建设、违规情况、市场干预情况等相关信息的披露管理。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2008"},{"stem":"市场竞争所需信息应当充分披露、交易机构对市场主体披露信息的真实性、准确性、及时性负责。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2009"},{"stem":"信息披露主体按照自定义格式通过信息披露平台向电力交易机构提供信息。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2010"},{"stem":"根据《电力市场信息披露基本规则》，电力市场信息只能通过信息披露平台进行披露，不能通过其他渠道发布。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2011"},{"stem":"保密管理在企业和组织中扮演着至关重要的角色，包括保护敏感信息、确保企业遵守法律法规、增强信任度等。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2012"},{"stem":"交易结算和纠纷处理是电力市场交易的无关环节，不影响经营主体的权益。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2013"},{"stem":"交易场所的安全稳定运行需要建立安全政策和标准操作程序，安全监测和日志记录机制，以及定期的安全评估和审计。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2014"},{"stem":"账号权限设置的目的是确保账号只能访问和操作其被授权的资源，通常采用基于角色的访问控制方法，将权限与角色相关联。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2015"},{"stem":"交易规则是由政府基于国家经济发展规律的客观要求和一定时期内国家产业现状和发展趋势，综合运用经济手段制定的对调整产业结构、指导行业发展和运行、提升行业国际竞争力等形成的一系列行动方案或行动准则的总称。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2016"},{"stem":"在部分现货正式运行的省份，中长期交易可以理解为带金融属性的差价合约方式。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2017"},{"stem":"当某一次的交易机会出现适合自身的价格信号时，激进的全仓投入做法未必会在未来的一段周期内取得最大的收益。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2018"},{"stem":"采取年度、月度、月内按照一定的电量比例进行交易，将收益和风险分摊到每个执行月份，给每次交易都留有机会。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2019"},{"stem":"下一个年度的市场交易组织，常常从月度交易最先开始。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2020"},{"stem":"电力价格是影响市场化用户用电量的重要因素。电力价格信号的引导作用使得用户在价格较高时减少用电。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2021"},{"stem":"随着经济的增长，企业生产和居民生活对电力的需求不断增加，从而推动用电量的增长。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2022"},{"stem":"不同产业的用电需求存在差异，但产业结构的变化并不会对市场化用户用电量产生影响。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2023"},{"stem":"对于用电企业在现货分区结算时，中长期合约尽量选择与自身用电地理区域一致或接近的发电企业，规避不同计量点带来的市场风险。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2024"},{"stem":"发电侧上下调预挂牌机制采用“报价不报量”方式，所有市场化机组均应当参与上下调报价。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2025"},{"stem":"根据《电力中长期交易基本规则》，电力用户拥有储能，或者电力用户参加特定时段的需求侧响应，由此产生的偏差电量，由电力用户自行承担。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2026"},{"stem":"电力中长期交易现阶段主要开展电能量交易，灵活开展发电权交易、合同转让交易，根据市场发展需要开展输电权、容量等交易。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2027"},{"stem":"集中式电力市场以中长期实物合约管理市场风险，配合现货交易采用全电量集中竞价的电力市场模式。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2028"},{"stem":"在分散式市场模式下，发电厂商利用中长期差价合约、日前及日内市场投标、实时平衡市场调增调减平衡机制投标来实现对自己发电计划曲线的决策和修正。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2029"},{"stem":"集中竞价交易指设置交易报价提交截止时间，电力交易平台汇总市场主体提交的交易申报信息，按照市场规则进行统一的市场出清，发布市场出清结果。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2030"},{"stem":"滚动撮合交易是指在规定的交易起止时间内，市场主体可以随时提交购电或者售电信息，电力交易平台按照时间优先、价格优先的原则进行滚动撮合成交。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2031"},{"stem":"挂牌交易指市场主体通过电力交易平台，将需求电量或者可供电量的数量和价格等信息对外发布要约，由符合资格要求的另一方提出接受该要约的申请。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2032"},{"stem":"同一市场主体可根据自身电力生产或者消费需要，购入或者售出电能量。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2033"},{"stem":"中长期中月度交易的标的物为当月电量（或者月度分时电量），条件具备的地区可组织开展针对年度内剩余月份的月度电量（或者月度分时电量）交易。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2034"},{"stem":"月内（多日）交易的标的物为月内剩余天数或者特定天数的电量（或者分时电量）。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2035"},{"stem":"当售电公司所有签约用户月度实际总用量偏离售电公司月度交易计划时，电力用户直接承担偏差电量电费。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2036"},{"stem":"电力交易中心负责绿色电力交易的结算工作，确保交易双方的权益得到保障。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2037"},{"stem":"绿色电力交易的价格完全由市场供求关系决定，政府不进行任何形式的干预。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2038"},{"stem":"绿色电力交易仅包括风电、光伏发电等新能源电力交易。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2039"},{"stem":"绿色电力环境价值按当月合同电量、发电企业上网电量、电力用户用电量三者取大的原则确定结算电量（以MWh为单位取整数，尾差不累计），以绿色电力环境价值结算，绿色电力环境价值偏差电量按照合同明确的绿色电力环境价值偏差补偿条款执行，由违约方向合同对方支付补偿费用。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2040"},{"stem":"若预测现货出清价格高于中长期市场合约价格，发电企业保持上限仓位，可在现货市场中获得高收益","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2041"},{"stem":"电力中长期交易结果判定方法主要包括事前预测、事中监控和事后复盘三个环节。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2042"},{"stem":"除国家有明确规定的情况外，双边协商交易原则上不进行限价。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2043"},{"stem":"发电商的实际电能生产量减去净电能交易量为差值为正，表明发电商向系统出售这一数量的多余电能。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2044"},{"stem":"电能量市场化交易（含省内和跨区跨省）价格不包括脱硫、脱硝、除尘和超低排放电价。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2045"},{"stem":"对于未来电力供应存在短缺风险的地区，可探索建立辅助服务市场，保障长期电力供应安全。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2046"},{"stem":"跨省跨区交易输电损耗原则上由卖方承担，也可由市场主体协商确定承担方式。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2047"},{"stem":"一般来说，供大于求时，电价可能下跌；而需大于供时，电价可能上涨。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2048"},{"stem":"集中竞价交易中，为避免市场操纵以及恶性竞争，可对结算价格设置上、下限。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2049"},{"stem":"根据《售电公司管理办法》，对于在多个省开展售电业务的售电公司，无需分别提交履约保函或保险。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2050"},{"stem":"待条件成熟时，探索开展电力期货和电力场外衍生品交易，为发电企业、售电主体和用户提供远期价格基准和风险管理手段。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2051"},{"stem":"加快建设以绿电交易为主的可再生能源消纳体系和绿色消费认证体系。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2052"},{"stem":"集中竞价交易可采用边际出清、高低匹配等价格形成机制。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2053"},{"stem":"跨区跨省的政府间协议原则上在上一年度的11月底前预测和下达总体电力电量规模和分月计划，由购售双方签订相应的购售电合同。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2054"},{"stem":"《售电公司管理办法》发改体改规〔2021〕1595号）规定，电力用户、售电公司与电网企业应签订三方电费结算补充协议，并签订售电公司、电力用户、电网企业三方合同。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2055"},{"stem":"美国PJM电力市场评价模型重点对市场行为和市场操纵力进行评估，防止形成市场垄断。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2056"},{"stem":"市场建设初期，我国可通过容量补偿机制起步，未来逐步探索建立容量市场。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2057"},{"stem":"享受国家补贴的可再生能源发电企业，参与电力市场时，市场交易价格高于（低于）当地燃煤基准电价部分，等额扣除（增加）国家补贴资金。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2058"},{"stem":"日内市场的主要作用在于为市场成员提供一个在日前市场关闭后对其发用电计划进行微调的交易平台，以应对日内的各种预测偏差及非计划状况，其交易规模往往较小。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2059"},{"stem":"实时市场则往往在小时前由调度中心组织实施，非常接近系统的实时运行，因而其主要作用并不在于电量交易，而在于为电力系统的阻塞管理和辅助服务提供调节手段与经济信号，真实反映系统超短期的资源稀缺程度与阻塞程度；并形成与系统实际运行切合度高的发用电计划，保证电网的安全运行。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2060"},{"stem":"分区边际电价模式适用于阻塞频繁发生在部分输电断面的地区。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2061"},{"stem":"《关于深化电力现货市场建设试点工作的意见》中指出，电力现货市场申报和出清限价设置应以促进用户侧削峰填谷、消纳清洁能源和防范价格异常波动为基本原则，避免因上下限设置不合理而影响价格信号发挥作用。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2062"},{"stem":"我国第一批现货试运行省份中，部分地区允许出清价格为负。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2063"},{"stem":"用电负荷大幅下降，风光新能源大发，市场竞价空间大幅压缩，导致市场出清价格降低。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2064"},{"stem":"对于电网阻塞程度较为严重、输电能力受限的地区，宜采用节点边际电价机制","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2065"},{"stem":"制定价格下限避免了市场主体在电力现货市场中的恶性竞争。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2066"},{"stem":"在市场化的电力体制中，上网电价和销售电价由竞争产生，而输配电价往往由监管机构进行独立核定。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2067"},{"stem":"在电力市场环境下，水电站除了发电成本外，还需要考虑其调节能力所带来的机会成本。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2068"},{"stem":"在电力市场环境下，风光资源具有零成本特性，新能源的发电边际成本较低甚至接近于零，因此新能源交易员的交易策略为申报高电价博取超额收益。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2069"},{"stem":"需求响应是指当电力批发市场价格升高或系统可靠性受威胁时，电力用户接收到供电方发出的诱导性减少负荷的直接补偿通知或者电力价格上升信号后，改变其固有的习惯用电模式，达到减少或者推移某时段的用电负荷而响应电力供应。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2070"},{"stem":"假设某时刻的负荷是由其前面邻近k个时段的负荷的线性组合，则自回归模型的阶数定为为k-1。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2071"},{"stem":"通过对不同用户用电负荷的预测，可以分析电力市场的供需状况，预测市场趋势，为电力交易商提供市场分析报告和投资建议。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2072"},{"stem":"政策变化、能源价格调整等法规因素对短期用电负荷几乎不产生影响。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2073"},{"stem":"尽可能深入地了解用户的用电习惯和行为模式，将这些因素纳入预测模型中，可以大幅提高模型的预测准确率。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2074"},{"stem":"常用的人工智能现货价格预测模型有支持向量机（SVM），人工神经网络（ANN），集成学习方法（随机森林、梯度提升树），长短期记忆网络（LSTM），自回归移动平均（ARIMA）模型。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2075"},{"stem":"边际成本是在某一机组出力条件下，每增加单位发电量所新增的成本。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2076"},{"stem":"固定成本是在某一机组出力条件下，每增加单位发电量所新增的成本。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2077"},{"stem":"电力辅助服务市场与电力现货市场相互独立，没有关系。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2078"},{"stem":"省调根据接收的联络线预计划进行省内预出清或预平衡，确定省间交易需求；国调中心、网调组织开展省间现货交易，实现省内与省间的第一次衔接。省间现货出清结果叠加中长期曲线作为省内现货市场正式出清的边界,省内以此为边界进行省内电力现货市场和辅助服务市场出清,实现省间与省内的第二次衔接。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2079"},{"stem":"电力现货市场交易仅在实时进行。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2080"},{"stem":"市场主体发现出清结果有误，应及时向市场运营机构反映。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2081"},{"stem":"省内现货市场边际收益测算不区分全量现货结算模式与差量现货结算模式","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2082"},{"stem":"对于火电企业，燃料成本是主要生产成本","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2083"},{"stem":"市场参与者预判运行日受极寒天气影响，但日前信息披露未考虑，会导致实时价格高于日前价格","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2084"},{"stem":"预测日前价格高于实时价格的负荷段，发电企业适当降低对应负荷段报价，多中标日前电量。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2085"},{"stem":"预测电能量出清价格较低时适合投入调频","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2086"},{"stem":"虚拟电厂应与火电、水电等其他各类经营主体公平参与市场竞争，平等享受市场权利与义务。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2087"},{"stem":"应根据虚拟电厂特性，单独设置或放宽虚拟电厂的市场准入要求。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2088"},{"stem":"对虚拟电厂创新探索应严格监管，从严控制虚拟电厂在市场交易中的套利行为。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2089"},{"stem":"就工商业用户来看，在厂房屋顶、空地建设集中式光伏发电设备，用于抵消白天的用电，是非常具有经济效益的一项投资。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2090"},{"stem":"光伏发电只有在白天，特别是中午时段满发的特性，和大多数电力用户实际用电并不在时段上完全对应。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2091"},{"stem":"光伏发电二类地区年度发电等效利用小时大于1600小时。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2092"},{"stem":"光伏发电一类地区年度发电等效利用小时在1400~1600小时。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2093"},{"stem":"光伏发电三类地区年度发电等效利用小时在1200~1400小时。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2094"},{"stem":"光伏系统发电量公式为：水平面太阳能总辐射量*光伏组件安装容量/标准条件下的辐射度*系统修正系数","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2095"},{"stem":"对于具备自发自用的电力用户，如果在现货市场出现非常低的负电价、或在特别时段，需求侧响应给与特别大的用电补贴的情况下，使用电网供电仍具有成本优势的可能。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2096"},{"stem":"对屋顶光伏的电力用户，其自用有余的电量上网，传统的方式是电网按照市场交易均价结算。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2097"},{"stem":"储能系统现在主流系统有1C、0.5C、0.25C三个，其充放时长分别为1小时、2小时、4小时","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2098"},{"stem":"放电深度是表示从蓄电池中放出的容量占该电池额定容量的比值大小,通常以放出的容量与电池额定容量之比的百分数表示。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2099"},{"stem":"蓄电池额定容量为10MWh,经放电后容量剩余1MWh,实际放出容量为9MWh,此时称该蓄电池的放电深度是10%。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2100"},{"stem":"某正常用电的工商业用户，配备屋顶光伏，上下网共用同一个关口计量表。某日零点，其电表下网示数为1234，上网示数为518，次日零点，其电表下网示数为2234，上网示数为618.电表倍率为1000。其计入电网供电的日用电量为1MWh。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2101"},{"stem":"某正常用电的工商业用户，配备屋顶光伏，上下网共用同一个关口计量表。某日零点，其电表下网示数为1234，上网示数为518，次日零点，其电表下网示数为2234，上网示数为618.电表倍率为1000。其当日上网电量为0.1MWh","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2102"},{"stem":"某正常用电的工商业用户，配备屋顶光伏，在用户进户关口和光伏设备出口分别计量。某日，光伏关口发电100kWh，用户总关口下网电量500kWh,上网60kWh。该用户当日实际用电为540kWh.","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2103"},{"stem":"某正常用电的工商业用户，配备屋顶光伏，在用户进户关口和光伏设备出口分别计量。某日，光伏关口发电100kWh，用户总关口下网电量500kWh,上网0kWh。该用户当日实际用电为600kWh","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2104"},{"stem":"某正常用电的工商业用户，配备屋顶光伏，在用户进户关口和光伏设备出口分别计量。某日，光伏关口发电100kWh，用户总关口下网电量0kWh,上网0kWh。该用户当日实际用电为100kWh","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2105"},{"stem":"某正常用电的工商业用户，配备屋顶光伏，在用户进户关口和光伏设备出口分别计量。某日，光伏关口发电100kWh，用户总关口下网电量0kWh,上网10kWh。该用户当日实际用电为90kWh","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2106"},{"stem":"某正常用电的工商业用户，配备屋顶光伏，在用户进户关口和光伏设备出口分别计量。某日，光伏关口发电100kWh，用户总关口下网电量500kWh,上网60kWh。现电网公司按照0.6元/kWh的供电价格和0.4元/kWh的光伏上网价格结算，该用户当日与电网公司结算实际电费支出为276元","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2107"},{"stem":"某正常用电的工商业用户，配备屋顶光伏，在用户进户关口和光伏设备出口分别计量。某日，光伏关口发电100kWh，用户总关口下网电量500kWh,上网0kWh。现电网公司按照0.6元/kWh的供电价格和0.4元/kWh的光伏上网价格结算，该用户当日与电网公司结算实际电费为300元","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2108"},{"stem":"某正常用电的工商业用户，配备屋顶光伏，在用户进户关口和光伏设备出口分别计量。某日，光伏关口发电100kWh，用户总关口下网电量0kWh,上网0kWh。现电网公司按照0.6元/kWh的供电价格和0.4元/kWh的光伏上网价格结算，该用户当日与电网公司结算实际电费为0","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2109"},{"stem":"绿电合同的电能量价格：指合同签订消纳绿电中，电能量的价格，包括绿证（环境权益价值）部分。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2110"},{"stem":"绿电合同的绿证（环境权益价值）价格：指合同签订消纳绿电中，绿证（环境权益价值）部分，不含电能量价格","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2111"},{"stem":"市场用户的用电价格由电能量交易价格、输配电价格（含辅助服务费用）、政府性基金及附加等构成。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2112"},{"stem":"管制定价的理论主要分为两类，即传统成本管制理论和激励性管制理论。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2113"},{"stem":"激励性管制的目标是实现全社会福利最大化。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2114"},{"stem":"根据进一步深化燃煤发电上网电价市场化改革的要求，要有序放开全部燃煤发电电量上网电价，“基准价+上下浮动”的价格机制已不再执行。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2115"},{"stem":"碳交易政策提升企业能效的主要驱动力是通过碳成本压力优化能耗","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2116"},{"stem":"数据清洗与预处理是数据挖掘的前置步骤，其目的是确保数据的准确性和一致性，以提高分析结果的质量。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2117"},{"stem":"特征选择与提取技术通过减少数据维度，帮助去除冗余信息，从而提高模型的训练效率和预测能力。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2118"},{"stem":"特征提取技术可显著提升模型的关键信息识别能力。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2119"},{"stem":"高新技术企业经营对电价水平变化的敏感性较低。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2120"},{"stem":"服务业企业经营对电价水平变化的敏感性较低。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2121"},{"stem":"提高附加值，通过技术创新和提升服务质量，是高新技术企业减轻电价波动影响的关键策略之一。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2122"},{"stem":"在市场竞争中，燃煤电厂之间开展的是完全信息博弈。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2123"},{"stem":"售电公司代理用户从发电商处购电，然后转卖给用户，从中赚取差价盈利。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2124"},{"stem":"同一电力用户与多个发电企业签约，若总用电量低于总合同电量，该电力用户对应于各发电企业的用电量应按各发电企业合同电量占总合同电量比重等比例调增。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2125"},{"stem":"聚合商用于结算的电能量部分上网电量为聚合的分布式发电主体实际上网电量合计值，聚合商用于结算的绿色电力环境价值部分电量为各分布式发电主体上网电量（以兆瓦时为单位取整数，在合同周期内尾差滚动到次月核算）的合计值。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2126"},{"stem":"绿证的单位是兆瓦时（MWh），每1兆瓦时的可再生能源电量对应1个绿证。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2127"},{"stem":"现阶段可交易绿证仅可交易一次。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2128"},{"stem":"电力用户未按时缴纳绿色电力环境价值费用时，电网企业应立即停止向其供电。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2129"},{"stem":"国外例如欧美的电力市场相比我国发展较早，因此我们可以充分借鉴国外企业进行市场开发的经验，直接应用到国内。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2130"},{"stem":"风险管理制度的编制过程中，监督和考核条款的设置仅是为了对员工进行约束，而非起到激励作用，且制度内容无需包含推动企业风险管理文化建设的相关内容。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2131"},{"stem":"电力供需偏差可分为短期和长期问题，短期电力供需不足通常与天气变化、设备故障、突发事件等因素有关。长期供需问题则可能与能源政策、市场经营主体装机容量和能源管理技术不足等因素相关。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2132"},{"stem":"VaR具体来说是指在给定持有期及置信度内，某一金融工具或投资组合所面临的最大损失。VaR模型的广泛应用表明它在金融（电力）市场风险度量方法的研究上有极大的优势。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2133"},{"stem":"在VaR模型中，持有期和置信水平是两个重要的参数，其取值是主观的，需要根据具体情况来设定。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2134"},{"stem":"电力市场的流动性风险涉及到市场经营主体在需要时能否迅速买卖电力，以及在交易过程中是否能够以合理的价格进行。由于电力产品的特殊性，其生产、传输和消费几乎是同步进行的，因此几乎不存在流动性风险。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2135"},{"stem":"在电力市场风险台账管理中，利用大数据分析和人工智能技术仅能提升风险台账的处理能力和分析水平，但无法实现风险预警功能。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2136"},{"stem":"电力交易员在编制市场交易管理相关文件时，主要关注文件的编制目的和依据，次要考虑行业自律的核心原则和价值观。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2137"},{"stem":"信用评估由国家主管部门、国家发展改革委统筹组织地方主管部门授权电力交易机构、第三方征信机构开展售电公司信用评价工作","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2138"},{"stem":"履约保函是一种金融担保工具，由银行或保险公司出具，保证在合同一方未能履行合同义务时，另一方可以获得经济赔偿。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2139"},{"stem":"中国电煤采购价格指数是反映报告期秦皇岛港及周边港口主流动力煤品种平仓交货价格水平的指标体系，由综合交易价、现货交易价和年度长协价三部分组成。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2140"},{"stem":"按照煤炭所在的市场，可以将煤炭价格类型划分为生产地价格、中转地价格和消费地价格。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2141"},{"stem":"从短期来看，天然气需求由整体经济和人口增长、环境政策、能源效率、科技变化、天然气和替代能源的价格关系所驱动。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2142"},{"stem":"美国亨利枢纽（HenryHub，HH）价格是整个北美天然气市场和部分全球液化天然气LNG市场的基准价，亨利枢纽位于路易斯安那州，是美国最具影响力的实体枢纽。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2143"},{"stem":"风力发电技术具有清洁低碳、环境成本低、资源可再生、永不枯竭、基建周期短、装机规模灵活等优点。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2144"},{"stem":"可再生能源由于变动成本低、有政策补贴，通常在市场中报低价以实现全部出清。可再生能源出力对市场的净负荷产生影响，进而影响市场供需关系和价格。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2145"},{"stem":"变动成本指与发电企业电能产量有直接关系的费用，这些费用不会随着电能产量的变化而变化，一般主要为燃料成本，包括空载成本和边际成本。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2146"},{"stem":"空载费用为发电机维持同步转速、输出电功率为零需要消耗的燃料费用，与出力水平无关，即机组在开机状态每个小时需要付出的成本。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2147"},{"stem":"电煤采购应坚持“长协为主，现货为辅”的原则，提升中长期合同在整体采购中占比，以现货比例的降低带动发电企业整体采购行为的不确定性同步下降，充分发挥中长期合同“压舱石”“稳定器”的作用。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2148"},{"stem":"电煤采购计划应结合发电企业实际情况，适当引入期货避险工具，确定合适的电煤采购及库存比例，从事煤炭期货套期保值操作，达到规避风险的目的。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2149"},{"stem":"应利用大数据、人工智能等技术，建立数字化煤炭采购管理平台，实现大数据流程化操作管理，提升电煤集中采购业务的专业水平，降低交易成本，提高采购效率。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2150"},{"stem":"年度、月度、月内合约比例不同，中长期合约收益的期望和标准差不同。不同的年度、月度、月内合约比例可构成中长期合约收益组合，所有中长期合约收益组合的集合即为中长期合约收益组合集。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2151"},{"stem":"当风险效用无差异曲线和中长期合约收益组合曲线相交时，交点即为最优的中长期合约收益组合，可确定最优的年度、月度、月内合约比例，即不同交易周期协同的交易组合策略。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2152"},{"stem":"在预测数据准确率相对较低的月度、多月甚至年度交易中，中长期曲线往往以直线、典型曲线为主，一般情况下不会对交易曲线有较多的差异化需求。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2153"},{"stem":"中长期合约为金融性质的差价合约，是控制现货市场风险，稳定盈利的关键。根据中长期市场的组成，可将中长期合约收益分解为年度交易、月度交易、月内交易等市场收益。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2154"},{"stem":"对自身中长期交易持仓情况分析，从时间周期角度分为月度、每日、每小时（分时段）中长期合约持仓量价情况分析。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2155"},{"stem":"电力辅助服务市场与电力现货市场具有强耦合性、具有功功率互补性、经济互斥性以及的出清模式的较大相关性。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2156"},{"stem":"电力现货市场和辅助服务市场单独出清模式下，一般先出清调频、旋转备用和非旋转备用，再出清电能量。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["错"],"levels":["技师"],"scope":"技师新增","id":"Q2157"},{"stem":"辅助服务的机会成本是指发电机组运行在电能量价格所对应的经济出力水平之上所产生的额外成本，或运行在电能量价格所对应的经济出力水平之下而放弃的利润。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2158"},{"stem":"电力现货市场与电力辅助服务市场具有有功功率互补性和经济互斥性。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2159"},{"stem":"将单位容量单位小时调频收益与电能量度电收益（度电收入与平均成本的差值）进行对比，可用于分析机组参与电能量市场收益高，还是参与调频市场收益高，可用于辅助服务交易策略分析制定。","type":"判断","options":[{"label":"对","text":"对"},{"label":"错","text":"错"}],"answer":["对"],"levels":["技师"],"scope":"技师新增","id":"Q2160"}]);
